option = {
  tooltip: {
    trigger: 'item',
    formatter: function(params) {
      if (params.componentSubType === 'custom') {
         return params.name;
      } 
      return params.data.name + ' (' + params.data.value[0] + ', ' + params.data.value[1] + ')';
    }
  },
  xAxis: {
    type: 'value',
    min: 0,
    max: 100,
    splitLine: { show: false }
  },
  yAxis: {
    type: 'value',
    min: 0,
    max: 100,
    splitLine: { show: false }
  },
  series: [
    {
      type: 'custom',
      renderItem: function (params, api) {
        if (params.context.rendered) return;
        params.context.rendered = true;

        const points = [];
        for (let i = 0; i < transformedData.length; i++) {
          points.push(api.coord([transformedData[i].x, transformedData[i].y]));
        }

        const w = params.coordSys.width;
        const h = params.coordSys.height;
        const xOffset = params.coordSys.x;
        const yOffset = params.coordSys.y;
        const bbox = { xl: xOffset, xr: xOffset + w, yt: yOffset, yb: yOffset + h };

        // Fortune's algorithm or an iterative plane intersection algorithm.
        // Here we use a Half-plane intersection approach for each point since N is small (N=10).
        function computeVoronoiCell(idx, points, bbox) {
          const p1 = points[idx];
          // Start with the bounding box as the initial polygon
          let poly = [
            [bbox.xl, bbox.yt],
            [bbox.xr, bbox.yt],
            [bbox.xr, bbox.yb],
            [bbox.xl, bbox.yb]
          ];

          for (let i = 0; i < points.length; i++) {
            if (i === idx) continue;
            const p2 = points[i];
            // Midpoint
            const mx = (p1[0] + p2[0]) / 2;
            const my = (p1[1] + p2[1]) / 2;
            // Normal vector (direction from p1 to p2)
            const nx = p2[0] - p1[0];
            const ny = p2[1] - p1[1];

            // Clip polygon against the half-plane defined by the perpendicular bisector
            const newPoly = [];
            for (let j = 0; j < poly.length; j++) {
              const a = poly[j];
              const b = poly[(j + 1) % poly.length];
              const aInside = (a[0] - mx) * nx + (a[1] - my) * ny <= 0;
              const bInside = (b[0] - mx) * nx + (b[1] - my) * ny <= 0;

              if (aInside) {
                 newPoly.push(a);
              }

              if (aInside !== bInside) {
                // Calculate intersection
                const v1x = b[0] - a[0];
                const v1y = b[1] - a[1];
                const v2x = -ny;
                const v2y = nx;

                // Line 1: (a[0], a[1]) + t * (v1x, v1y)
                // Line 2: (mx, my) + s * (v2x, v2y)
                const det = v1x * v2y - v1y * v2x;
                if (Math.abs(det) > 1e-9) {
                  const ix = mx - a[0];
                  const iy = my - a[1];
                  const t = (ix * v2y - iy * v2x) / det;
                  newPoly.push([a[0] + t * v1x, a[1] + t * v1y]);
                }
              }
            }
            poly = newPoly;
          }
          return poly;
        }

        const polygons = [];
        for (let i = 0; i < points.length; i++) {
          const cell = computeVoronoiCell(i, points, bbox);
          if (cell.length > 2) {
            polygons.push({
                type: 'polygon',
                shape: {
                    points: cell
                },
                style: api.style({
                    fill: echarts.color.modifyHSL('#5470c6', Math.round((i / points.length) * 360)),
                    stroke: '#fff',
                    lineWidth: 1.5,
                    opacity: 0.6
                })
            });
          }
        }

        return {
          type: 'group',
          children: polygons
        };
      },
      itemStyle: { },
      data: transformedData.map((item, idx) => ({ name: item.name, value: [item.x, item.y, idx] }))
    },
    {
      name: 'Points',
      type: 'scatter',
      symbolSize: 8,
      itemStyle: { color: '#000', shadowBlur: 2, shadowColor: 'rgba(0,0,0,0.5)' },
      data: transformedData.map(function(item) {
        return {
          name: item.name,
          value: [item.x, item.y]
        };
      })
    }
  ]
};
